"use client";

import { useState } from "react";

// shadcn
import { Button } from "@/components/ui/button";

// assets
import { CheckIcon, XIcon } from "lucide-react";

type Feature = { label: string; included: boolean };

const plans: {
  id: number;
  name: string;
  monthly: number;
  yearly: number;
  features: Feature[];
  featured: boolean;
}[] = [
  {
    id: 1,
    name: "Personal",
    monthly: 24,
    yearly: 19,
    features: [
      { label: "20 Gb", included: true },
      { label: "25 Users", included: true },
      { label: "50 CP", included: false },
      { label: "1 Active Sessions", included: false }
    ],
    featured: false
  },
  {
    id: 2,
    name: "Team",
    monthly: 49,
    yearly: 39,
    features: [
      { label: "20 Gb", included: true },
      { label: "25 Users", included: true },
      { label: "50 CP", included: true },
      { label: "1 Active Sessions", included: false }
    ],
    featured: true
  },
  {
    id: 3,
    name: "Enterprise",
    monthly: 99,
    yearly: 79,
    features: [
      { label: "20 Gb", included: true },
      { label: "25 Users", included: true },
      { label: "50 CP", included: true },
      { label: "1 Active Sessions", included: true }
    ],
    featured: false
  }
];

//  ------------------------------ | PRICING 4 | ------------------------------  //

export default function Pricing4() {
  const [billing, setBilling] = useState<"monthly" | "yearly">("monthly");

  return (
    <section className="py-20 bg-primary">
      <div className="container mx-auto px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-8 flex flex-col gap-6">
          <h2 className="text-primary-foreground">Select Your Plan</h2>

          {/* Monthly / Yearly toggle */}
          <div className="flex items-center justify-center gap-4">
            <Button
              variant="ghost"
              onClick={() => setBilling("monthly")}
              className={`p-0 h-auto hover:bg-transparent dark:hover:bg-transparent text-sm font-semibold transition-colors ${billing === "monthly" ? "text-primary-foreground hover:text-primary-foreground" : "text-primary-foreground/50 hover:text-primary-foreground"}`}
            >
              Monthly
            </Button>
            <Button
              variant="ghost"
              onClick={() => setBilling("yearly")}
              className={`p-0 h-auto hover:bg-transparent dark:hover:bg-transparent text-sm font-semibold transition-colors ${billing === "yearly" ? "text-primary-foreground hover:text-primary-foreground" : "text-primary-foreground/50 hover:text-primary-foreground"}`}
            >
              Yearly
            </Button>
          </div>
        </div>

        {/* Plans grid */}
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
          {plans.map((plan) => (
            <div
              key={plan.id}
              className={`bg-background rounded-2xl p-8 flex flex-col items-center text-center gap-6 ${plan.featured ? "border-2 border-yellow-500" : ""}`}
            >
              {/* Plan name */}
              <h4 className="text-foreground font-bold">{plan.name}</h4>

              {/* Price */}
              <div className="flex items-end gap-1.5">
                <span className="text-4xl font-bold text-foreground">
                  ${billing === "monthly" ? plan.monthly : plan.yearly}
                </span>
                <span className="text-muted-foreground text-md mb-1">
                  /per month
                </span>
              </div>

              {/* Features */}
              <ul className="flex flex-col gap-2 w-full">
                {plan.features.map((feature) => (
                  <li
                    key={feature.label}
                    className="flex items-center justify-center gap-2"
                  >
                    {feature.included ? (
                      <CheckIcon className="size-4 text-primary shrink-0" />
                    ) : (
                      <XIcon className="size-4 text-primary/40 shrink-0" />
                    )}
                    <span
                      className={`text-md ${feature.included ? "text-foreground" : "text-muted-foreground line-through"}`}
                    >
                      {feature.label}
                    </span>
                  </li>
                ))}
              </ul>

              {/* CTA */}
              <Button
                className={
                  plan.featured
                    ? "bg-yellow-500 text-white hover:bg-yellow-500/90 w-full"
                    : "bg-transparent border border-yellow-500 text-yellow-500 hover:bg-transparent hover:text-yellow-500 w-full"
                }
                variant={plan.featured ? "default" : "outline"}
              >
                Get Started
              </Button>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
